def _validate_config():
    """Validate that required configuration is present."""
    if not ENCRYPTION_KEY:
        raise ValueError("ENCRYPTION_KEY environment variable must be set")
    if not SERVICE_API_KEY:
        raise ValueError("SERVICE_API_KEY environment variable must be set")
    if not REDIS_PASSWORD:
        logger.warning("REDIS_PASSWORD is not set - connecting without authentication")


def _compute_hmac(data: str) -> str:
    """Compute HMAC-SHA256 for data integrity verification."""
    return hmac.new(
        ENCRYPTION_KEY.encode('utf-8'),
        data.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()


def _sign_data(data: str) -> str:
    """Sign data with HMAC for integrity verification."""
    signature = _compute_hmac(data)
    return json.dumps({"data": data, "sig": signature})


def _verify_and_extract(signed_data: str) -> Optional[str]:
    """Verify HMAC signature and extract data."""
    try:
        parsed = json.loads(signed_data)
        data = parsed["data"]
        signature = parsed["sig"]
        expected_sig = _compute_hmac(data)
        if hmac.compare_digest(signature, expected_sig):
            return data
        logger.warning("Data integrity check failed - signature mismatch")
        return None
    except (json.JSONDecodeError, KeyError) as e:
        logger.error(f"Failed to verify data: {e}")
        return None


class RedisClusterManager:
    """Manages connections to a Redis cluster with retry logic and health checks."""

    def __init__(self):
        self._cluster: Optional[RedisCluster] = None
        self._connected = False
        self._last_health_check = 0
        self._health_check_interval = 30  # seconds

    def _parse_nodes(self) -> list:
        """Parse Redis node addresses from configuration."""
        nodes = []
        for node_str in REDIS_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def connect(self) -> RedisCluster:
        """Establish connection to Redis cluster with SSL and authentication."""
        if self._cluster and self._connected:
            return self._cluster

        nodes = self._parse_nodes()
        logger.info(f"Connecting to Redis cluster nodes: {REDIS_NODES}")

        connection_kwargs = {
            "startup_nodes": nodes,
            "password": REDIS_PASSWORD if REDIS_PASSWORD else None,
            "socket_timeout": REDIS_SOCKET_TIMEOUT,
            "socket_connect_timeout": REDIS_SOCKET_TIMEOUT,
            "retry_on_timeout": REDIS_RETRY_ON_TIMEOUT,
            "max_connections": REDIS_MAX_CONNECTIONS,
            "decode_responses": True,
            "skip_full_coverage_check": True,
        }

        if REDIS_USE_SSL:
            connection_kwargs.update({
                "ssl": True,
                "ssl_ca_certs": REDIS_SSL_CA_CERTS,
                "ssl_certfile": REDIS_SSL_CERTFILE,
                "ssl_keyfile": REDIS_SSL_KEYFILE,
                "ssl_cert_reqs": "required",
            })
            logger.info("SSL/TLS enabled for Redis connections")

        max_retries = 3
        for attempt in range(1, max_retries + 1):
            try:
                self._cluster = RedisCluster(**connection_kwargs)
                # Verify connection
                self._cluster.ping()
                self._connected = True
                logger.info("Successfully connected to Redis cluster")
                return self._cluster
            except (ConnectionError, TimeoutError, RedisError) as e:
                logger.error(f"Redis connection attempt {attempt}/{max_retries} failed: {e}")
                if attempt == max_retries:
                    raise
                time.sleep(2 ** attempt)  # Exponential backoff

    def get_client(self) -> RedisCluster:
        """Get Redis cluster client, reconnecting if necessary."""
        if not self._cluster or not self._connected:
            return self.connect()

        # Periodic health check
        now = time.time()
        if now - self._last_health_check > self._health_check_interval:
            try:
                self._cluster.ping()
                self._last_health_check = now
            except (ConnectionError, TimeoutError, RedisError):
                logger.warning("Redis health check failed, reconnecting...")
                self._connected = False
                return self.connect()

        return self._cluster

    def close(self):
        """Close Redis cluster connection."""
        if self._cluster:
            try:
                self._cluster.close()
            except Exception as e:
                logger.error(f"Error closing Redis connection: {e}")
            finally:
                self._cluster = None
                self._connected = False
                logger.info("Redis cluster connection closed")

    def health_check(self) -> Dict[str, Any]:
        """Perform a health check on the Redis cluster."""
        try:
            client = self.get_client()
            start = time.time()
            client.ping()
            latency_ms = (time.time() - start) * 1000

            cluster_info = client.cluster_info()
            return {
                "status": "healthy",
                "latency_ms": round(latency_ms, 2),
                "cluster_state": cluster_info.get("cluster_state", "unknown"),
                "cluster_slots_assigned": cluster_info.get("cluster_slots_assigned", 0),
                "cluster_known_nodes": cluster_info.get("cluster_known_nodes", 0),
            }
        except Exception as e:
            return {
                "status": "unhealthy",
                "error": str(e),
            }


class SessionManager:
    """Manages user session tokens in Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self.redis = redis_manager

    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> Dict[str, str]:
        """Create a new session token for a user."""
        client = self.redis.get_client()
        session_token = secrets.token_urlsafe(48)
        session_id = hashlib.sha256(session_token.encode()).hexdigest()

        session_data = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "metadata": metadata or {},
        }

        signed_data = _sign_data(json.dumps(session_data))
        key = f"{KEY_PREFIX_SESSION}{session_id}"

        try:
            client.setex(key, SESSION_TOKEN_TTL, signed_data)
            logger.info(f"Session created for user {user_id}, TTL={SESSION_TOKEN_TTL}s")
            return {
                "session_token": session_token,
                "session_id": session_id,
                "expires_in": SESSION_TOKEN_TTL,
            }
        except RedisError as e:
            logger.error(f"Failed to create session: {e}")
            raise

    def validate_session(self, session_token: str) -> Optional[Dict]:
        """Validate a session token and return session data."""
        client = self.redis.get_client()
        session_id = hashlib.sha256(session_token.encode()).hexdigest()
        key = f"{KEY_PREFIX_SESSION}{session_id}"

        try:
            signed_data = client.get(key)
            if not signed_data:
                logger.info(f"Session not found or expired: {session_id[:16]}...")
                return None

            data = _verify_and_extract(signed_data)
            if not data:
                logger.warning(f"Session data integrity check failed: {session_id[:16]}...")
                client.delete(key)
                return None

            session_data = json.loads(data)
            # Refresh TTL on access (sliding expiration)
            client.expire(key, SESSION_TOKEN_TTL)
            return session_data
        except RedisError as e:
            logger.error(f"Failed to validate session: {e}")
            raise

    def revoke_session(self, session_token: str) -> bool:
        """Revoke a session token."""
        client = self.redis.get_client()
        session_id = hashlib.sha256(session_token.encode()).hexdigest()
        key = f"{KEY_PREFIX_SESSION}{session_id}"

        try:
            result = client.delete(key)
            # Also add to revocation list for distributed awareness
            revoked_key = f"{KEY_PREFIX_REVOKED}{session_id}"
            client.setex(revoked_key, SESSION_TOKEN_TTL, "1")
            logger.info(f"Session revoked: {session_id[:16]}...")
            return result > 0
        except RedisError as e:
            logger.error(f"Failed to revoke session: {e}")
            raise

    def revoke_all_user_sessions(self, user_id: str) -> int:
        """Revoke all sessions for a user (uses scan for safety)."""
        client = self.redis.get_client()
        count = 0
        try:
            cursor = 0
            while True:
                cursor, keys = client.scan(cursor=cursor, match=f"{KEY_PREFIX_SESSION}*", count=100)
                for key in keys:
                    signed_data = client.get(key)
                    if signed_data:
                        data = _verify_and_extract(signed_data)
                        if data:
                            session_data = json.loads(data)
                            if session_data.get("user_id") == user_id:
                                client.delete(key)
                                count += 1
                if cursor == 0:
                    break
            logger.info(f"Revoked {count} sessions for user {user_id}")
            return count
        except RedisError as e:
            logger.error(f"Failed to revoke user sessions: {e}")
            raise


class APIKeyManager:
    """Manages API keys in Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self.redis = redis_manager

    def create_api_key(self, user_id: str, name: str, scopes: list,
                       ttl: Optional[int] = None) -> Dict[str, str]:
        """Create a new API key for a user."""
        client = self.redis.get_client()
        api_key = f"sk_{secrets.token_urlsafe(42)}"
        key_id = hashlib.sha256(api_key.encode()).hexdigest()
        effective_ttl = ttl if ttl else API_KEY_TTL

        key_data = {
            "user_id": user_id,
            "name": name,
            "scopes": scopes,
            "key_id": key_id,
            "created_at": datetime.utcnow().isoformat(),
        }

        signed_data = _sign_data(json.dumps(key_data))
        redis_key = f"{KEY_PREFIX_API_KEY}{key_id}"

        try:
            client.setex(redis_key, effective_ttl, signed_data)

            # Store mapping of user -> api keys for management
            user_keys_key = f"{KEY_PREFIX_API_KEY}user:{user_id}"
            client.sadd(user_keys_key, key_id)
            client.expire(user_keys_key, effective_ttl + 3600)  # Extra buffer

            logger.info(f"API key created for user {user_id}, name={name}, TTL={effective_ttl}s")
            return {
                "api_key": api_key,
                "key_id": key_id,
                "name": name,
                "scopes": scopes,
                "expires_in": effective_ttl,
            }
        except RedisError as e:
            logger.error(f"Failed to create API key: {e}")
            raise

    def validate_api_key(self, api_key: str) -> Optional[Dict]:
        """Validate an API key and return key data."""
        client = self.redis.get_client()
        key_id = hashlib.sha256(api_key.encode()).hexdigest()
        redis_key = f"{KEY_PREFIX_API_KEY}{key_id}"

        try:
            # Check revocation first
            revoked_key = f"{KEY_PREFIX_REVOKED}{key_id}"
            if client.exists(revoked_key):
                logger.warning(f"Revoked API key used: {key_id[:16]}...")
                return None

            signed_data = client.get(redis_key)
            if not signed_data:
                return None

            data = _verify_and_extract(signed_data)
            if not data:
                logger.warning(f"API key data integrity check failed: {key_id[:16]}...")
                client.delete(redis_key)
                return None

            return json.loads(data)
        except RedisError as e:
            logger.error(f"Failed to validate API key: {e}")
            raise

    def revoke_api_key(self, api_key: str) -> bool:
        """Revoke an API key."""
        client = self.redis.get_client()
        key_id = hashlib.sha256(api_key.encode()).hexdigest()
        redis_key = f"{KEY_PREFIX_API_KEY}{key_id}"

        try:
            # Get key data before deletion to find user_id
            signed_data = client.get(redis_key)
            if signed_data:
                data = _verify_and_extract(signed_data)
                if data:
                    key_data = json.loads(data)
                    user_id = key_data.get("user_id")
                    if user_id:
                        user_keys_key = f"{KEY_PREFIX_API_KEY}user:{user_id}"
                        client.srem(user_keys_key, key_id)

            result = client.delete(redis_key)
            # Add to revocation list
            revoked_key = f"{KEY_PREFIX_REVOKED}{key_id}"
            client.setex(revoked_key, API_KEY_TTL, "1")
            logger.info(f"API key revoked: {key_id[:16]}...")
            return result > 0
        except RedisError as e:
            logger.error(f"Failed to revoke API key: {e}")
            raise

    def list_user_api_keys(self, user_id: str) -> list:
        """List all API key IDs for a user (not the actual keys)."""
        client = self.redis.get_client()
        user_keys_key = f"{KEY_PREFIX_API_KEY}user:{user_id}"

        try:
            key_ids = client.smembers(user_keys_key)
            result = []
            for key_id in key_ids:
                redis_key = f"{KEY_PREFIX_API_KEY}{key_id}"
                signed_data = client.get(redis_key)
                if signed_data:
                    data = _verify_and_extract(signed_data)
                    if data:
                        key_data = json.loads(data)
                        ttl = client.ttl(redis_key)
                        result.append({
                            "key_id": key_id,
                            "name": key_data.get("name"),
                            "scopes": key_data.get("scopes"),
                            "created_at": key_data.get("created_at"),
                            "ttl_remaining": ttl,
                        })
                else:
                    # Clean up stale reference
                    client.srem(user_keys_key, key_id)
            return result
        except RedisError as e:
            logger.error(f"Failed to list API keys: {e}")
            raise


class RefreshTokenManager:
    """Manages refresh tokens in Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self.redis = redis_manager

    def create_refresh_token(self, user_id: str, session_id: str) -> Dict[str, str]:
        """Create a new refresh token."""
        client = self.redis.get_client()
        refresh_token = secrets.token_urlsafe(64)
        token_id = hashlib.sha256(refresh_token.encode()).hexdigest()

        token_data = {
            "user_id": user_id,
            "session_id": session_id,
            "created_at": datetime.utcnow().isoformat(),
            "used": False,
        }

        signed_data = _sign_data(json.dumps(token_data))
        key = f"{KEY_PREFIX_REFRESH_TOKEN}{token_id}"

        try:
            client.setex(key, REFRESH_TOKEN_TTL, signed_data)
            logger.info(f"Refresh token created for user {user_id}")
            return {
                "refresh_token": refresh_token,
                "token_id": token_id,
                "expires_in": REFRESH_TOKEN_TTL,
            }
        except RedisError as e:
            logger.error(f"Failed to create refresh token: {e}")
            raise

    def use_refresh_token(self, refresh_token: str) -> Optional[Dict]:
        """Use a refresh token (one-time use with rotation)."""
        client = self.redis.get_client()
        token_id = hashlib.sha256(refresh_token.encode()).hexdigest()
        key = f"{KEY_PREFIX_REFRESH_TOKEN}{token_id}"

        try:
            # Use a pipeline for atomic check-and-delete
            pipe = client.pipeline()
            pipe.get(key)
            pipe.delete(key)
            results = pipe.execute()

            signed_data = results[0]
            if not signed_data:
                return None

            data = _verify_and_extract(signed_data)
            if not data:
                return None

            token_data = json.loads(data)
            if token_data.get("used"):
                logger.warning(f"Refresh token reuse detected: {token_id[:16]}...")
                return None

            logger.info(f"Refresh token used for user {token_data['user_id']}")
            return token_data
        except RedisError as e:
            logger.error(f"Failed to use refresh token: {e}")
            raise


class RateLimiter:
    """Rate limiting using Redis sliding window."""

    def __init__(self, redis_manager: RedisClusterManager):
        self.redis = redis_manager

    def check_rate_limit(self, identifier: str, max_requests: int = 100,
                         window_seconds: int = None) -> Dict[str, Any]:
        """Check and update rate limit for an identifier."""
        client = self.redis.get_client()
        window = window_seconds if window_seconds else RATE_LIMIT_TTL
        key = f"{KEY_PREFIX_RATE_LIMIT}{identifier}"

        try:
            pipe = client.pipeline()
            pipe.incr(key)
            pipe.ttl(key)
            results = pipe.execute()

            current_count = results[0]
            current_ttl = results[1]

            # Set TTL on first request
            if current_ttl == -1:
                client.expire(key, window)
                current_ttl = window

            allowed = current_count <= max_requests
            remaining = max(0, max_requests - current_count)

            return {
                "allowed": allowed,
                "limit": max_requests,
                "remaining": remaining,
                "reset_in": current_ttl,
                "current_count": current_count,
            }
        except RedisError as e:
            logger.error(f"Failed to check rate limit: {e}")
            # Fail open - allow request if Redis is down
            return {
                "allowed": True,
                "limit": max_requests,
                "remaining": max_requests,
                "reset_in": window,
                "error": "rate_limit_unavailable",
            }


class UserProfileCache:
    """Cache for user profile data."""

    def __init__(self, redis_manager: RedisClusterManager):
        self.redis = redis_manager

    def cache_profile(self, user_id: str, profile_data: Dict) -> bool:
        """Cache user profile data."""
        client = self.redis.get_client()
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"

        # Remove sensitive fields before caching
        safe_data = {k: v for k, v in profile_data.items()
                     if k not in ("password", "password_hash", "ssn", "credit_card")}

        try:
            signed_data = _sign_data(json.dumps(safe_data))
            client.setex(key, USER_PROFILE_CACHE_TTL, signed_data)
            return True
        except RedisError as e:
            logger.error(f"Failed to cache user profile: {e}")
            return False

    def get_profile(self, user_id: str) -> Optional[Dict]:
        """Get cached user profile data."""
        client = self.redis.get_client()
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"

        try:
            signed_data = client.get(key)
            if not signed_data:
                return None

            data = _verify_and_extract(signed_data)
            if not data:
                return None

            return json.loads(data)
        except RedisError as e:
            logger.error(f"Failed to get cached profile: {e}")
            return None

    def invalidate_profile(self, user_id: str) -> bool:
        """Invalidate cached user profile."""
        client = self.redis.get_client()
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"

        try:
            client.delete(key)
            return True
        except RedisError as e:
            logger.error(f"Failed to invalidate profile cache: {e}")
            return False


