def require_service_auth(f):
    """Decorator to require service-level authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("X-Service-API-Key", "")
        if not auth_header or not hmac.compare_digest(auth_header, SERVICE_API_KEY):
            return jsonify({"error": "unauthorized", "message": "Invalid service API key"}), 401
        return f(*args, **kwargs)
    return decorated


def require_rate_limit(max_requests=100, window=60):
    """Decorator to apply rate limiting."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            identifier = request.headers.get("X-Forwarded-For", request.remote_addr)
            result = rate_limiter.check_rate_limit(identifier, max_requests, window)

            g.rate_limit_info = result

            if not result["allowed"]:
                response = jsonify({
                    "error": "rate_limit_exceeded",
                    "message": "Too many requests",
                    "retry_after": result["reset_in"],
                })
                response.status_code = 429
                response.headers["X-RateLimit-Limit"] = str(result["limit"])
                response.headers["X-RateLimit-Remaining"] = str(result["remaining"])
                response.headers["X-RateLimit-Reset"] = str(result["reset_in"])
                return response

            return f(*args, **kwargs)
        return decorated
    return decorator


@app.after_request
def add_rate_limit_headers(response):
    """Add rate limit headers to all responses."""
    rate_info = getattr(g, 'rate_limit_info', None)
    if rate_info:
        response.headers["X-RateLimit-Limit"] = str(rate_info.get("limit", ""))
        response.headers["X-RateLimit-Remaining"] = str(rate_info.get("remaining", ""))
        response.headers["X-RateLimit-Reset"] = str(rate_info.get("reset_in", ""))
    return response


