@app.teardown_appcontext
def shutdown_redis(exception=None):
    """Clean up Redis connection on app shutdown."""
    pass  # Connection managed by RedisClusterManager


def create_app():
    """Application factory."""
    _validate_config()
    redis_manager.connect()
    return app


if __name__ == "__main__":
    try:
        application = create_app()
        port = int(os.environ.get("PORT", "8080"))
        host = os.environ.get("HOST", "0.0.0.0")
        debug = os.environ.get("DEBUG", "false").lower() == "true"

        logger.info(f"Starting cache microservice on {host}:{port}")
        application.run(host=host, port=port, debug=debug)
    except Exception as e:
        logger.critical(f"Failed to start service: {e}")
        raise
    finally:
        redis_manager.close()